// Input transcript
const transcript = $('Webhook').first().json.body.transcription_text || "";

// Regex patterns for sensitive data
const patterns = {
  SSN: /\b\d{3}-\d{2}-\d{4}\b/g,
  CREDIT_CARD: /\b(?:\d[ -]*?){13,16}\b/g,
  PHONE: /\b(?:\+?\d{1,3}[-.\s]?)?(?:\(?\d{3}\)?[-.\s]?)\d{3}[-.\s]?\d{4}\b/g,
  EMAIL: /\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b/gi,
};

// Audit log
const auditLog = [];

// Redaction function
let redactedTranscript = transcript;

for (const [type, regex] of Object.entries(patterns)) {
  const matches = transcript.match(regex);

  if (matches) {
    matches.forEach(match => {
      auditLog.push({
        type,
        value: match.replace(/.(?=.{4})/g, "*"), // partially mask for audit
        timestamp: new Date().toISOString(),
      });
    });

    redactedTranscript = redactedTranscript.replace(
      regex,
      `[REDACTED_${type}]`
    );
  }
}

// Return result
return [
  {
    json: {
      redactedTranscript,
      redactionAudit: auditLog,
      redactionCount: auditLog.length,
    }
  }
];

