const query = `
MATCH (internal:Person {email: $internalEmail})
MATCH (external:Person {email: $externalEmail})
MERGE (internal)-[r:COMMUNICATES_WITH]-(external)
ON CREATE SET
  r.totalCalls = 1,
  r.count_30d = 1,
  r.decayed = 1,
  r.tieStrength = 1,
  r.last_seen = datetime()
ON MATCH SET
  r.totalCalls = coalesce(r.totalCalls, 0) + 1,
  r.count_30d = $newCount30d,
  r.decayed = $newDecayed,
  r.tieStrength = $newTieStrength,
  r.last_seen = datetime()

`;

const parameters = {
  internalEmail:$('Set values').first().json.value2,
  externalEmail:$('Set values').first().json.value2,
  newCount30d:$input.first().json.newDecayed,
  newDecayed:$input.first().json.newCount30d,
  newTieStrength: $input.first().json.newTieStrength



};

return [
  {
    json: {
      statement: JSON.stringify(query),
      parameters: JSON.stringify(parameters)
    }
  }
];

const result = $input.first().json;

const now = new Date();
const decayFactor = 0.95;

let newDecayed;
let newCount30d;
let newTieStrength;

if (!result.data.values || result.data.values.length === 0) {

  // Relationship does NOT exist
  newDecayed = 1;
  newCount30d = 1;
  newTieStrength = 1;   // First interaction

} else {

  const record = result.data.values[0];

  const existingCount30d = record[0] || 0;
  const existingDecayed = record[1] || 0;
  const lastSeen = new Date(record[2]);

  const timeDiffDays = (now - lastSeen) / (1000 * 60 * 60 * 24);

  const decayedValue =
    existingDecayed * Math.pow(decayFactor, timeDiffDays);

  newDecayed = decayedValue + 1;
  newCount30d = existingCount30d + 1;


  newTieStrength = newDecayed;  
}

return [
  {
    json: {
      newDecayed,
      newCount30d,
      newTieStrength
    }
  }
];

