for (const contactId in contacts) {
  const contact = contacts[contactId];

  const coreEmail = contact?.fields?.core?.email?.value;
  if (coreEmail) emailSet.add(coreEmail.toLowerCase().trim());

  const allEmail = contact?.fields?.all?.email;
  if (allEmail) emailSet.add(allEmail.toLowerCase().trim());

  const notesRaw = contact?.fields?.core?.contactnotesjson1?.value;
  if (notesRaw) {
    try {
      const notes = JSON.parse(notesRaw);
      if (notes?.data?.work_email) emailSet.add(notes.data.work_email.toLowerCase().trim());
